const p = $json.profile || {};
const issues = [];
if (!p.height_cm) issues.push('Height missing');
if (!p.weight_kg) issues.push('Weight missing');
if (p.weight_kg && (p.weight_kg < 25 || p.weight_kg > 300)) issues.push('Weight unrealistic, confirm value');
if (p.height_cm && (p.height_cm < 100 || p.height_cm > 240)) issues.push('Height unrealistic, confirm value');
if (p.medical_constraints && p.medical_constraints !== 'none') issues.push('Medical constraints noted: include safety disclaimer');
return [{ json: { ...$json, validation_issues: issues, is_valid: issues.length === 0 } }];
